module RefModule(clk, rst, wIn, ld, wOut);input clk,rst, ld;
  input [1:0] wIn;
  output reg [2:0] wOut;
    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk, posedge rst or posedge dbg_halt)begin
    if (rst) wOut <= 0;
    else if (ld) wOut <= 2*wIn;
    else wOut <= wOut;
  end
endmodule
